function SplashScreen({ onDone }) {
    const [exiting, setExiting] = useState(false);
    const [showSkip, setShowSkip] = useState(false);

    useEffect(() => {
        const skipTimer = setTimeout(() => setShowSkip(true), 900);
        const autoTimer = setTimeout(() => handleDismiss(), 3200);
        return () => {
            clearTimeout(skipTimer);
            clearTimeout(autoTimer);
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    function handleDismiss() {
        setExiting(true);
        setTimeout(onDone, 550);
    }

    return (
        <div
            className="fixed inset-0 z-50 flex items-center justify-center overflow-hidden"
            style={{
                background: "#09090B",
                opacity: exiting ? 0 : 1,
                transform: exiting ? "scale(1.04)" : "scale(1)",
                transition: "opacity 0.55s ease, transform 0.55s ease",
                pointerEvents: exiting ? "none" : "auto",
            }}
        >
            {/* drifting color field */}
            <div
                className="absolute -inset-32 pointer-events-none"
                style={{
                    background:
                        "radial-gradient(circle at 50% 50%, rgba(99,102,241,0.35) 0%, rgba(99,102,241,0.08) 35%, transparent 65%)",
                    filter: "blur(60px)",
                    animation: "drift 14s ease-in-out infinite",
                }}
            />

            {/* fine grid, fading out radially */}
            <div
                className="absolute inset-0 pointer-events-none"
                style={{
                    backgroundImage:
                        "linear-gradient(rgba(255,255,255,0.03) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.03) 1px, transparent 1px)",
                    backgroundSize: "56px 56px",
                    maskImage:
                        "radial-gradient(circle at 50% 50%, black 0%, transparent 70%)",
                    WebkitMaskImage:
                        "radial-gradient(circle at 50% 50%, black 0%, transparent 70%)",
                }}
            />

            <ConvergingLines />
            <OrbitRings />

            <div className="relative z-10 flex flex-col items-center px-6">
                <div
                    className="relative mb-8"
                    style={{ animation: "logoPulse 4s ease-in-out infinite" }}
                >
                    <div
                        className="absolute -inset-10 rounded-full pointer-events-none"
                        style={{
                            background:
                                "radial-gradient(circle, rgba(165,180,252,0.4) 0%, transparent 70%)",
                            filter: "blur(24px)",
                        }}
                    />
                    <img
                        src={LOGO_SRC}
                        alt="rn-shadcn"
                        className="relative w-32 sm:w-40 h-auto"
                        draggable={false}
                    />
                </div>

                <div style={{ animation: "fadeUp 0.8s cubic-bezier(.16,1,.3,1) 0.3s both" }}>
                    <p className="text-zinc-500 font-mono text-sm tracking-widest uppercase text-center">
                        shadcn/ui, made for touch
                    </p>
                </div>
            </div>

            <button
                onClick={handleDismiss}
                className="absolute bottom-8 right-8 text-xs font-mono text-zinc-500 hover:text-zinc-300 border border-zinc-800 hover:border-zinc-600 rounded-full px-3.5 py-1.5 transition-all duration-300"
                style={{
                    opacity: showSkip ? 1 : 0,
                    transform: showSkip ? "translateY(0)" : "translateY(6px)",
                    transition: "opacity 0.4s ease, transform 0.4s ease, color 0.2s, border-color 0.2s",
                }}
            >
                Skip →
            </button>

            <div
                className="absolute inset-0 pointer-events-none"
                style={{
                    background:
                        "radial-gradient(circle at 50% 50%, transparent 30%, #09090B 90%)",
                }}
            />
        </div>
    );
}

